import React, { useState, useEffect } from 'react';
import api from '../services/api';

const ITEM_STYLE = (active) => ({
  display: 'flex',
  alignItems: 'center',
  gap: 10,
  cursor: 'pointer',
  padding: '10px 16px',
  background: active ? '#ebf8ff' : '#fff',
  border: `2px solid ${active ? '#3182ce' : '#e2e8f0'}`,
  borderRadius: 10,
  transition: 'all 0.15s',
  userSelect: 'none',
  fontFamily: 'Tahoma, sans-serif',
  fontSize: 14,
  fontWeight: active ? 600 : 400,
  color: active ? '#2b6cb0' : '#4a5568',
});

const PREVIEW_LABEL = {
  fontWeight: 700,
  color: '#2d3748',
  marginBottom: 8,
  fontSize: 14,
  fontFamily: 'Tahoma, sans-serif',
  display: 'flex',
  alignItems: 'center',
  gap: 6,
};

export default function ReportModal({ patient, measurements, onClose }) {
  const [templates, setTemplates]           = useState([]);
  const [selectedTpl, setSelectedTpl]       = useState(null);
  const [customPrompt, setCustomPrompt]     = useState('');
  const [sendItems, setSendItems]           = useState({
    table:  true,
    chart:  measurements.length >= 2,
    report: true,
  });
  const [generating, setGenerating] = useState(false);
  const [sending, setSending]       = useState(false);
  const [report, setReport]         = useState(null);
  const [editedText, setEditedText] = useState('');
  const [error, setError]           = useState('');
  const [success, setSuccess]       = useState('');
  const [step, setStep]             = useState('compose');

  useEffect(() => {
    api.get('/messaging/templates').then(r => {
      setTemplates(r.data);
      if (r.data.length > 0) setSelectedTpl(r.data[0]);
    }).catch(() => {});
  }, []);

  const effectivePrompt = customPrompt.trim() || selectedTpl?.text || '';
  const canGenerate = sendItems.table || sendItems.chart || sendItems.report;
  const promptNeeded = sendItems.report && !effectivePrompt;

  const generate = async () => {
    if (promptNeeded) { setError('لطفاً یک قالب گزارش انتخاب کنید یا دستورالعمل سفارشی بنویسید.'); return; }
    setError('');
    setGenerating(true);
    try {
      const res = await api.post('/messaging/generate-report', {
        patient_id:     patient.id,
        prompt:         sendItems.report ? effectivePrompt : '',
        include_chart:  sendItems.chart,
        include_table:  sendItems.table,
        include_report: sendItems.report,
      });
      setReport(res.data);
      setEditedText(res.data.report_text || '');
      setStep('preview');
    } catch (e) {
      const err = e.response?.data;
      if (err?.retry) {
        setError('سرویس هوش مصنوعی موقتاً در دسترس نیست. لطفاً دوباره تلاش کنید.');
      } else {
        setError(err?.error || 'خطا در تولید گزارش.');
      }
    } finally {
      setGenerating(false);
    }
  };

  const send = async () => {
    setSending(true);
    setError('');
    try {
      const res = await api.post('/messaging/send', {
        patient_id:   patient.id,
        message:      editedText,
        chart_base64: report?.chart_base64 || null,
        table_base64: report?.table_base64 || null,
        send_report:  sendItems.report && !!editedText,
        send_chart:   sendItems.chart  && !!report?.chart_base64,
        send_table:   sendItems.table  && !!report?.table_base64,
      });
      const { sent, failed } = res.data;
      const sentLabels = { table: 'جدول', chart: 'نمودار', report: 'گزارش' };
      const sentStr = sent.map(s => sentLabels[s]).join('، ');
      setSuccess(`✅ با موفقیت ارسال شد: ${sentStr}${failed.length ? ` (خطا در: ${failed.map(f=>sentLabels[f]).join('، ')})` : ''}`);
      setTimeout(onClose, 2800);
    } catch (e) {
      setError(e.response?.data?.error || 'خطا در ارسال. توکن ربات یا شناسه چت را بررسی کنید.');
    } finally {
      setSending(false);
    }
  };

  const toggle = (key) => setSendItems(s => ({ ...s, [key]: !s[key] }));

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal modal-lg" onClick={e => e.stopPropagation()}
        style={{ maxWidth: 760 }}>

        {/* Header */}
        <div className="modal-header" style={{
          background: 'linear-gradient(135deg, #1a365d 0%, #2b6cb0 100%)',
          color: '#fff', borderRadius: 'var(--radius) var(--radius) 0 0',
        }}>
          <div>
            <h2 style={{ color: '#fff', marginBottom: 2 }}>📊 گزارش و ارسال به بله</h2>
            <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.75)',
              fontFamily: 'Tahoma, sans-serif' }}>
              {patient.name} — شناسه بله: {patient.bale_chat_id || '(متصل نشده)'}
            </div>
          </div>
          <button className="modal-close"
            style={{ color: '#fff', background: 'rgba(255,255,255,0.15)',
              border: 'none', borderRadius: '50%', width: 32, height: 32 }}
            onClick={onClose}>×</button>
        </div>

        <div className="modal-body">
          {error && (
            <div className="alert alert-error" style={{ marginBottom: 16 }}>
              ⚠ {error}
              {error.includes('تلاش') && (
                <button className="btn btn-sm btn-warning" style={{ marginRight: 10 }}
                  onClick={generate}>🔄 تلاش مجدد</button>
              )}
            </div>
          )}
          {success && (
            <div className="alert alert-success" style={{ marginBottom: 16 }}>{success}</div>
          )}

          {step === 'compose' ? (
            <>
              {/* What to send */}
              <div style={{ background: '#f8fafc', border: '1px solid #e2e8f0',
                borderRadius: 12, padding: '16px 20px', marginBottom: 20 }}>
                <div style={{ fontWeight: 700, marginBottom: 12, color: '#1a202c',
                  fontSize: 14, fontFamily: 'Tahoma, sans-serif' }}>
                  انتخاب محتوا برای ارسال
                </div>
                <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
                  <label style={ITEM_STYLE(sendItems.table)}>
                    <input type="checkbox" checked={sendItems.table}
                      onChange={() => toggle('table')}
                      style={{ display: 'none' }} />
                    <span style={{ fontSize: 18 }}>📋</span>
                    جدول اندازه‌گیری‌ها
                  </label>
                  <label style={{
                    ...ITEM_STYLE(sendItems.chart),
                    opacity: measurements.length < 2 ? 0.5 : 1,
                  }}>
                    <input type="checkbox" checked={sendItems.chart}
                      onChange={() => measurements.length >= 2 && toggle('chart')}
                      style={{ display: 'none' }}
                      disabled={measurements.length < 2} />
                    <span style={{ fontSize: 18 }}>📈</span>
                    نمودار پیشرفت
                    {measurements.length < 2 && (
                      <small style={{ color: '#a0aec0', fontSize: 11 }}>(نیاز به ۲+ ویزیت)</small>
                    )}
                  </label>
                  <label style={ITEM_STYLE(sendItems.report)}>
                    <input type="checkbox" checked={sendItems.report}
                      onChange={() => toggle('report')}
                      style={{ display: 'none' }} />
                    <span style={{ fontSize: 18 }}>🤖</span>
                    گزارش هوش مصنوعی
                  </label>
                </div>
              </div>

              {/* Prompt section (only if AI report selected) */}
              {sendItems.report && (
                <>
                  <div className="form-group">
                    <label className="form-label" style={{ fontFamily: 'Tahoma, sans-serif' }}>
                      قالب گزارش
                    </label>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 10 }}>
                      {templates.map(t => (
                        <button key={t.id}
                          className={`btn btn-sm ${selectedTpl?.id === t.id && !customPrompt ? 'btn-primary' : 'btn-ghost'}`}
                          style={{ fontFamily: 'Tahoma, sans-serif', fontSize: 13 }}
                          onClick={() => { setSelectedTpl(t); setCustomPrompt(''); }}>
                          {t.label}
                        </button>
                      ))}
                    </div>
                    {selectedTpl && !customPrompt && (
                      <div style={{
                        fontSize: 13, color: '#4a5568', background: '#f7fafc',
                        padding: '10px 14px', borderRadius: 8,
                        borderRight: '3px solid #3182ce',
                        fontFamily: 'Tahoma, sans-serif',
                        direction: 'rtl', lineHeight: 1.7,
                      }}>
                        {selectedTpl.description}
                      </div>
                    )}
                  </div>

                  <div className="form-group">
                    <label className="form-label" style={{ fontFamily: 'Tahoma, sans-serif' }}>
                      دستورالعمل سفارشی <span className="text-muted">(اختیاری — جایگزین قالب بالا می‌شود)</span>
                    </label>
                    <textarea className="form-textarea" rows={3}
                      placeholder="دستورالعمل ویژه خود را اینجا بنویسید…"
                      value={customPrompt}
                      onChange={e => setCustomPrompt(e.target.value)}
                      style={{ fontFamily: 'Tahoma, sans-serif', direction: 'rtl', lineHeight: 1.7 }} />
                  </div>
                </>
              )}
            </>
          ) : (
            /* Preview step */
            <>
              {report?.table_base64 && sendItems.table && (
                <div style={{ marginBottom: 24 }}>
                  <div style={PREVIEW_LABEL}>📋 جدول اندازه‌گیری‌ها</div>
                  <img src={`data:image/png;base64,${report.table_base64}`}
                    alt="Measurement table"
                    style={{ maxWidth: '100%', borderRadius: 10,
                      border: '1px solid #e2e8f0',
                      boxShadow: '0 4px 16px rgba(0,0,0,0.08)' }} />
                </div>
              )}

              {report?.chart_base64 && sendItems.chart && (
                <div style={{ marginBottom: 24 }}>
                  <div style={PREVIEW_LABEL}>📈 نمودار پیشرفت</div>
                  <img src={`data:image/png;base64,${report.chart_base64}`}
                    alt="Progress chart"
                    style={{ maxWidth: '100%', borderRadius: 10,
                      border: '1px solid #e2e8f0',
                      boxShadow: '0 4px 16px rgba(0,0,0,0.08)' }} />
                </div>
              )}

              {sendItems.report && (
                <div className="form-group">
                  <div style={{ ...PREVIEW_LABEL, marginBottom: 10 }}>
                    📝 متن گزارش هوش مصنوعی
                    <span style={{ fontSize: 12, fontWeight: 400, color: '#718096' }}>
                      (قابل ویرایش قبل از ارسال)
                    </span>
                  </div>
                  <textarea className="form-textarea" rows={12}
                    value={editedText}
                    onChange={e => setEditedText(e.target.value)}
                    style={{
                      fontFamily: 'Tahoma, Vazir, sans-serif',
                      direction: 'rtl',
                      lineHeight: 1.9,
                      fontSize: 14,
                      background: '#fafbfc',
                    }} />
                </div>
              )}

              <div style={{
                background: '#ebf8ff', border: '1px solid #90cdf4',
                borderRadius: 10, padding: '12px 16px', fontSize: 13,
                fontFamily: 'Tahoma, sans-serif', direction: 'rtl',
                color: '#2b6cb0',
              }}>
                📲 ارسال به <strong>{patient.name}</strong> از طریق پیام‌رسان بله
                (شناسه: {patient.bale_chat_id})
              </div>
            </>
          )}
        </div>

        {/* Footer */}
        <div className="modal-footer">
          <button className="btn btn-ghost"
            style={{ fontFamily: 'Tahoma, sans-serif' }}
            onClick={step === 'compose' ? onClose : () => setStep('compose')}>
            {step === 'compose' ? 'انصراف' : '← بازگشت'}
          </button>

          {step === 'compose' ? (
            <button className="btn btn-primary"
              style={{ fontFamily: 'Tahoma, sans-serif', minWidth: 160 }}
              onClick={generate}
              disabled={generating || !canGenerate || promptNeeded}>
              {generating
                ? <><span className="spinner" /> در حال پردازش…</>
                : '✨ تولید پیش‌نمایش'}
            </button>
          ) : (
            <button className="btn btn-success"
              style={{ fontFamily: 'Tahoma, sans-serif', minWidth: 160 }}
              onClick={send}
              disabled={sending || !!success}>
              {sending
                ? <><span className="spinner" /> در حال ارسال…</>
                : '📤 ارسال به بله'}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
